#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    int *x1 = (int *)a;
    int *x2 = (int *)b;
    return x1[0] - x2[0];
}

int main() {
    int N;
    scanf("%d", &N);
    int points[N][2];
    for (int i = 0; i < N; i++) {
        scanf("%d %d", &points[i][0], &points[i][1]);
    }
    qsort(points, N, sizeof(points[0]), compare);
    long long maxArea = 0;
    for (int i = 0; i < N; i++) {
        for (int j = i + 1; j < N; j++) {
            int minX = points[i][0];
            int maxX = points[j][0];
            int minY = 500;
            for (int k = 0; k < N; k++) {
                if (points[k][0] >= minX && points[k][0] <= maxX) {
                    minY = (minY < points[k][1]) ? minY : points[k][1];
                }
            }
            long long area = (long long)(maxX - minX) * (long long)minY;
            if (area > maxArea) {
                maxArea = area;
            }
        }
    }
    printf("%lld\n", maxArea);
    return 0;
}

