const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];

const N = parseInt(readline());
const points = [];
for (let i = 0; i < N; i++) {
    const [x, y] = readline().split(' ').map(Number);
    points.push([x, y]);
}
points.sort((a, b) => a[0] - b[0]);
let maxArea = 0;
for (let i = 0; i < N; i++) {
    for (let j = i + 1; j < N; j++) {
        const minX = points[i][0];
        const maxX = points[j][0];
        let minY = 500;
        for (let k = 0; k < N; k++) {
            if (points[k][0] >= minX && points[k][0] <= maxX) {
                minY = Math.min(minY, points[k][1]);
            }
        }
        const area = (maxX - minX) * minY;
        if (area > maxArea) {
            maxArea = area;
        }
    }
}
